'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import Image from 'next/image'
import { createClient } from '@/lib/supabase/client'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { toast } from 'sonner'
import { Eye, EyeOff, LogIn, UserPlus, Loader2, Lock } from 'lucide-react'

// CONFIGURACAO: Definir como false para reabilitar o registro de contas
const REGISTRATION_DISABLED = true

export default function LoginPage() {
    const router = useRouter()
    const [email, setEmail] = useState('')
    const [password, setPassword] = useState('')
    const [confirmPassword, setConfirmPassword] = useState('')
    const [fullName, setFullName] = useState('')
    const [showPassword, setShowPassword] = useState(false)
    const [showConfirmPassword, setShowConfirmPassword] = useState(false)
    const [loading, setLoading] = useState(false)
    const [forgotPasswordMode, setForgotPasswordMode] = useState(false)
    const [forgotPasswordEmail, setForgotPasswordEmail] = useState('')
    const [sendingResetEmail, setSendingResetEmail] = useState(false)

    const handleForgotPassword = async (e: React.FormEvent) => {
        e.preventDefault()
        setSendingResetEmail(true)

        try {
            const supabase = createClient()
            const redirectUrl = `${window.location.origin}/reset-password`

            const { error } = await supabase.auth.resetPasswordForEmail(forgotPasswordEmail, {
                redirectTo: redirectUrl,
            })

            if (error) {
                toast.error(error.message)
                return
            }

            toast.success('Verifique sua caixa de entrada para redefinir sua senha.')
            setForgotPasswordMode(false)
            setForgotPasswordEmail('')
        } catch {
            toast.error('Tente novamente em alguns instantes.')
        } finally {
            setSendingResetEmail(false)
        }
    }

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault()
        setLoading(true)

        try {
            const supabase = createClient()
            const { data, error } = await supabase.auth.signInWithPassword({
                email,
                password,
            })

            if (error) {
                if (error.message.includes('Email not confirmed') || error.message.includes('email_not_confirmed')) {
                    toast.error('Voce precisa confirmar seu email antes de fazer login. Verifique sua caixa de entrada.')
                } else if (error.message === 'Invalid login credentials' || error.status === 400) {
                    toast.error('Email ou senha incorretos.')
                } else {
                    toast.error(error.message)
                }
                return
            }

            if (data?.user) {
                await new Promise(resolve => setTimeout(resolve, 500))

                const { data: profileData, error: profileError } = await supabase
                    .from('profiles')
                    .select('id, email, full_name, role')
                    .eq('id', data.user.id)
                    .single()

                if (profileError || !profileData) {
                    toast.error('Usuario autenticado mas perfil nao encontrado. Entre em contato com o administrador.')
                    await supabase.auth.signOut()
                    return
                }
            }

            toast.success('Login realizado com sucesso!')
            router.push('/')
            router.refresh()
        } catch {
            toast.error('Tente novamente em alguns instantes.')
        } finally {
            setLoading(false)
        }
    }

    const handleSignUp = async (e: React.FormEvent) => {
        e.preventDefault()

        if (password !== confirmPassword) {
            toast.error('As senhas nao coincidem.')
            return
        }

        if (password.length < 6) {
            toast.error('A senha deve ter pelo menos 6 caracteres.')
            return
        }

        setLoading(true)

        try {
            const supabase = createClient()
            const { error } = await supabase.auth.signUp({
                email,
                password,
                options: {
                    emailRedirectTo: `${window.location.origin}/`,
                    data: {
                        full_name: fullName,
                    }
                }
            })

            if (error) {
                if (error.message.includes('Email not confirmed') || error.message.includes('email_not_confirmed')) {
                    toast.error('Verifique sua caixa de entrada para confirmar seu email antes de fazer login.')
                } else if (error.message === 'User already registered') {
                    toast.error('Este email ja esta cadastrado. Tente fazer login ou recuperar sua senha.')
                } else {
                    toast.error(error.message)
                }
                return
            }

            toast.success('Cadastro realizado com sucesso!')
            router.push('/')
        } catch {
            toast.error('Tente novamente em alguns instantes.')
        } finally {
            setLoading(false)
        }
    }

    // Forgot Password Mode
    if (forgotPasswordMode) {
        return (
            <div className="w-full min-h-screen lg:grid lg:grid-cols-2">
                <div className="flex items-center justify-center py-12">
                    <div className="mx-auto grid w-[350px] gap-6">
                        <Card className="border-0 shadow-none">
                            <CardHeader className="text-left space-y-2">
                                <div className="flex items-center gap-3">
                                    <Image
                                        src="/dashmed-logo.png"
                                        alt="Logo"
                                        width={40}
                                        height={40}
                                        className="w-10 h-10"
                                    />
                                    <div>
                                        <CardTitle className="text-2xl font-bold text-foreground">Recuperar Senha</CardTitle>
                                        <CardDescription>
                                            Digite seu email para receber o link de recuperacao
                                        </CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent>
                                <form onSubmit={handleForgotPassword} className="space-y-4">
                                    <div className="space-y-2">
                                        <Label htmlFor="forgot-email">Email</Label>
                                        <Input
                                            id="forgot-email"
                                            type="email"
                                            value={forgotPasswordEmail}
                                            onChange={(e) => setForgotPasswordEmail(e.target.value)}
                                            placeholder="seu@email.com"
                                            required
                                        />
                                    </div>

                                    <Button
                                        type="submit"
                                        className="w-full"
                                        disabled={sendingResetEmail}
                                    >
                                        {sendingResetEmail ? (
                                            <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                        ) : null}
                                        Enviar Link de Recuperacao
                                    </Button>

                                    <Button
                                        type="button"
                                        variant="ghost"
                                        className="w-full"
                                        onClick={() => setForgotPasswordMode(false)}
                                    >
                                        Voltar para o Login
                                    </Button>
                                </form>
                            </CardContent>
                        </Card>
                    </div>
                </div>
                <div className="hidden bg-muted lg:flex items-center justify-center p-12 text-center">
                    <div className="space-y-4">
                        <Image
                            src="/dashmed-logo.png"
                            alt="DashMed Pro Logo"
                            width={96}
                            height={96}
                            className="w-24 h-24 mx-auto"
                        />
                        <h1 className="text-3xl font-bold text-foreground">DashMed Pro</h1>
                        <p className="text-muted-foreground">
                            Recupere o acesso a sua conta.
                        </p>
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="w-full min-h-screen lg:grid lg:grid-cols-2">
            <div className="flex items-center justify-center py-12">
                <div className="mx-auto grid w-[350px] gap-6">
                    <Card className="border-0 shadow-none">
                        <CardHeader className="text-left space-y-2">
                            <div className="flex items-center gap-3">
                                <Image
                                    src="/dashmed-logo.png"
                                    alt="DashMed Pro Logo"
                                    width={40}
                                    height={40}
                                    className="w-10 h-10"
                                />
                                <div>
                                    <CardTitle className="text-2xl font-bold text-foreground">Bem-vindo</CardTitle>
                                    <CardDescription>
                                        Acesse ou crie sua conta na plataforma
                                    </CardDescription>
                                </div>
                            </div>
                        </CardHeader>
                        <CardContent>
                            <Tabs defaultValue="login" className="space-y-4">
                                <TabsList className="grid w-full grid-cols-2">
                                    <TabsTrigger value="login">Login</TabsTrigger>
                                    <TabsTrigger value="signup" disabled={REGISTRATION_DISABLED}>Cadastro</TabsTrigger>
                                </TabsList>

                                <TabsContent value="login">
                                    <form onSubmit={handleLogin} className="space-y-4">
                                        <div className="space-y-2">
                                            <Label htmlFor="login-email">Email</Label>
                                            <Input
                                                id="login-email"
                                                type="email"
                                                value={email}
                                                onChange={(e) => setEmail(e.target.value)}
                                                placeholder="seu@email.com"
                                                required
                                            />
                                        </div>

                                        <div className="space-y-2">
                                            <div className="flex items-center">
                                                <Label htmlFor="login-password">Senha</Label>
                                                <button
                                                    type="button"
                                                    onClick={() => setForgotPasswordMode(true)}
                                                    className="ml-auto inline-block text-sm underline hover:text-primary"
                                                >
                                                    Esqueceu sua senha?
                                                </button>
                                            </div>
                                            <div className="relative">
                                                <Input
                                                    id="login-password"
                                                    type={showPassword ? 'text' : 'password'}
                                                    value={password}
                                                    onChange={(e) => setPassword(e.target.value)}
                                                    placeholder="Sua senha"
                                                    required
                                                />
                                                <Button
                                                    type="button"
                                                    variant="ghost"
                                                    size="sm"
                                                    className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                                                    onClick={() => setShowPassword(!showPassword)}
                                                >
                                                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                                </Button>
                                            </div>
                                        </div>

                                        <Button
                                            type="submit"
                                            className="w-full"
                                            disabled={loading}
                                        >
                                            {loading ? (
                                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                            ) : (
                                                <LogIn className="mr-2 h-4 w-4" />
                                            )}
                                            Entrar
                                        </Button>
                                    </form>
                                </TabsContent>

                                <TabsContent value="signup">
                                    {REGISTRATION_DISABLED ? (
                                        <div className="space-y-4 text-center py-8">
                                            <Lock className="h-12 w-12 mx-auto text-muted-foreground" />
                                            <h3 className="text-lg font-medium">Cadastro Temporariamente Indisponivel</h3>
                                            <p className="text-sm text-muted-foreground">
                                                O registro de novas contas esta temporariamente desabilitado.
                                                Entre em contato com o administrador para obter acesso.
                                            </p>
                                        </div>
                                    ) : (
                                        <form onSubmit={handleSignUp} className="space-y-4">
                                            <div className="space-y-2">
                                                <Label htmlFor="signup-name">Nome Completo</Label>
                                                <Input
                                                    id="signup-name"
                                                    type="text"
                                                    value={fullName}
                                                    onChange={(e) => setFullName(e.target.value)}
                                                    placeholder="Seu nome completo"
                                                />
                                            </div>

                                            <div className="space-y-2">
                                                <Label htmlFor="signup-email">Email</Label>
                                                <Input
                                                    id="signup-email"
                                                    type="email"
                                                    value={email}
                                                    onChange={(e) => setEmail(e.target.value)}
                                                    placeholder="seu@email.com"
                                                    required
                                                />
                                            </div>

                                            <div className="space-y-2">
                                                <Label htmlFor="signup-password">Senha</Label>
                                                <div className="relative">
                                                    <Input
                                                        id="signup-password"
                                                        type={showPassword ? 'text' : 'password'}
                                                        value={password}
                                                        onChange={(e) => setPassword(e.target.value)}
                                                        placeholder="Minimo 6 caracteres"
                                                        required
                                                    />
                                                    <Button
                                                        type="button"
                                                        variant="ghost"
                                                        size="sm"
                                                        className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                                                        onClick={() => setShowPassword(!showPassword)}
                                                    >
                                                        {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                                    </Button>
                                                </div>
                                            </div>

                                            <div className="space-y-2">
                                                <Label htmlFor="confirm-password">Confirmar Senha</Label>
                                                <div className="relative">
                                                    <Input
                                                        id="confirm-password"
                                                        type={showConfirmPassword ? 'text' : 'password'}
                                                        value={confirmPassword}
                                                        onChange={(e) => setConfirmPassword(e.target.value)}
                                                        placeholder="Confirme sua senha"
                                                        required
                                                    />
                                                    <Button
                                                        type="button"
                                                        variant="ghost"
                                                        size="sm"
                                                        className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                                                        onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                                                    >
                                                        {showConfirmPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                                                    </Button>
                                                </div>
                                            </div>

                                            <Button
                                                type="submit"
                                                className="w-full"
                                                disabled={loading}
                                            >
                                                {loading ? (
                                                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                                ) : (
                                                    <UserPlus className="mr-2 h-4 w-4" />
                                                )}
                                                Criar Conta
                                            </Button>
                                        </form>
                                    )}
                                </TabsContent>
                            </Tabs>
                        </CardContent>
                    </Card>
                </div>
            </div>
            <div className="hidden bg-muted lg:flex items-center justify-center p-12 text-center">
                <div className="space-y-4">
                    <Image
                        src="/dashmed-logo.png"
                        alt="DashMed Pro Logo"
                        width={96}
                        height={96}
                        className="w-24 h-24 mx-auto"
                    />
                    <h1 className="text-3xl font-bold text-foreground">DashMed Pro</h1>
                    <p className="text-muted-foreground">
                        A plataforma completa para impulsionar o seu negocio.
                    </p>
                </div>
            </div>
        </div>
    )
}
